#!/bin/bash
mask=$((0xffffffff << (32 - $2))) ; sub="$(((mask >> 24) & 255)).$(((mask >> 16) & 255)).$(((mask >> 8) & 255)).$(((mask) & 255))" ; IFS=. read ip1 ip2 ip3 ip4 <<<"$1" ; IFS=. read m1 m2 m3 m4 <<<"$sub" ; first_ip="$((ip1 & m1)).$((ip2 & m2)).$((ip3 & m3)).$(((ip4 & m4)+1))" ; IFS=. read ip1 ip2 ip3 ip4 <<<"$1" ; IFS=. read m1 m2 m3 m4 <<<"$sub" ; last_ip="$((ip1 | ((~m1) & 255))).$((ip2 | ((~m2) & 255))).$((ip3 | ((~m3) & 255))).$(((ip4 | ((~m4) & 255))-1))" ; echo -n "$first_ip - $last_ip"
